trait AwsCredentialManager {
  def getCredentialsProvider: AwsCredentialsProvider
  def refreshCredentials(): Try[AwsCredentialsProvider]
}

class DefaultAwsCredentialManager(strategy: CredentialStrategy) extends AwsCredentialManager {

  override def getCredentialsProvider: AwsCredentialsProvider = strategy match {
    case DefaultChain =>
      DefaultCredentialsProvider.builder()
        .reuseLastProviderEnabled(true)
        .build()

    case EnvironmentVariables =>
      EnvironmentVariableCredentialsProvider.create()

    case InstanceProfile =>
      InstanceProfileCredentialsProvider.builder()
        .build()

    case AssumeRole(roleArn, sessionName) =>
      createAssumeRoleProvider(roleArn, sessionName)

    case ProfileBased(profileName) =>
      ProfileCredentialsProvider.builder()
        .profileName(profileName)
        .build()
  }

  override def refreshCredentials(): Try[AwsCredentialsProvider] = Try {
    getCredentialsProvider
  }

  private def createAssumeRoleProvider(roleArn: String, sessionName: String): AwsCredentialsProvider = {
    val stsClient = StsClient.builder()
      .region(Region.US_EAST_1)
      .credentialsProvider(DefaultCredentialsProvider.create())
      .build()

    val assumeRoleRequest = AssumeRoleRequest.builder()
      .roleArn(roleArn)
      .roleSessionName(sessionName)
      .durationSeconds(3600)
      .build()

    val assumeRoleResponse = stsClient.assumeRole(assumeRoleRequest)
    val credentials = assumeRoleResponse.credentials()

    StaticCredentialsProvider.create(
      AwsSessionCredentials.create(
        credentials.accessKeyId(),
        credentials.secretAccessKey(),
        credentials.sessionToken()
      )
    )
  }
}

